mapper.update:
UPDATE tb_book_item
SET item_status = 'LOANED'
WHERE item_no = #{itemNo}

UPDATE tb_book_item
SET item_status = 'AVAILABLE'
WHERE item_no = (
    SELECT item_no FROM tb_loan WHERE loan_no = #{loanNo}
)

mapper.select:
SELECT COUNT(*)
FROM tb_loan
WHERE member_id = #{memberId}

SELECT COUNT(*)
FROM tb_loan l
JOIN tb_book_item i ON l.item_no = i.item_no
WHERE l.member_id = #{memberId}
AND i.book_no = #{bookNo}
AND l.loan_status = 'LOAN'
